import{_ as o,o as i,c as t,a2 as a}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"RFC-015 — LEARN-link rollout","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-015.md","filePath":"rfc/RFC-015.md"}'),n={name:"rfc/RFC-015.md"};function r(l,e,s,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-015-—-learn-link-rollout" tabindex="-1">RFC-015 — LEARN-link rollout <a class="header-anchor" href="#rfc-015-—-learn-link-rollout" aria-label="Permalink to &quot;RFC-015 — LEARN-link rollout&quot;">​</a></h1><blockquote><p>Status · Closed (planning carried into ADR-051 + Milestones L-A through L-E) Author · product Closes into · ADR-051 (outbound learn-link stewardship) Slice gate · v0.5.0 Why this is an RFC · The audit in <a href="./../research/learn-link-audit"><code>docs/research/learn-link-audit.md</code></a> shows that 76 % of outbound LEARN-tab links go to NASA + Wikipedia, and only 4 % to non-US agency sites. Fixing that is more than a data change — it is a contract decision (which sources are allowed, which language wins for a given user, what gets shown on the public page) and a pipeline decision (when to fail-close, where to integrate the link-checker). RFC-015 is the planning record; ADR-051 is the lock.</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-046 (May 2026) corrected the imagery side: agency-first build-time fetching with NASA Images API + curated Wikimedia as fallbacks. ADR-047 (also May 2026) added per-image and per-text-fragment provenance with a fail-closed pipeline and a public <code>/credits</code> page.</p><p>Outbound LEARN-tab links — visible on every primary detail panel — were not covered. The audit shows the same drift pattern that motivated ADR-046:</p><ul><li>925 outbound links inventoried.</li><li>76 % to NASA-domain + Wikipedia.</li><li>4 % to non-US agency sites.</li><li>Zero native-language links to operator portals despite their existence.</li><li>No per-link provenance, no <code>hreflang</code>, no <code>rel=&quot;external&quot;</code>, no link-checker.</li></ul><p>The user-visible cost is real: a researcher landing on a Chang&#39;e or Tianwen-1 detail panel today is sent to Wikipedia first, when the operating agency publishes its own English and Chinese pages. The project is downstream of the world&#39;s space agencies; we should send users <em>to</em> them, not past them.</p><h2 id="open-questions-resolved" tabindex="-1">Open Questions (resolved) <a class="header-anchor" href="#open-questions-resolved" aria-label="Permalink to &quot;Open Questions (resolved)&quot;">​</a></h2><h3 id="oq-1-—-one-contract-or-two" tabindex="-1">OQ-1 — One contract or two? <a class="header-anchor" href="#oq-1-—-one-contract-or-two" aria-label="Permalink to &quot;OQ-1 — One contract or two?&quot;">​</a></h3><p><strong>Question.</strong> Should outbound link stewardship live as an <em>extension</em> to ADR-047, or as its own ADR?</p><p><strong>Decision.</strong> Own ADR (ADR-051). ADR-047&#39;s manifest model is the right pattern, but the data shape, the fair-player rendering rules (rel attributes, hreflang), the locale fallback chain, and the public surface (<code>/library</code>) are distinct enough from imagery that a self-contained ADR is clearer. ADR-051 cites ADR-047 as the parent contract.</p><h3 id="oq-2-—-allow-wikipedia-only-entities" tabindex="-1">OQ-2 — Allow Wikipedia-only entities? <a class="header-anchor" href="#oq-2-—-allow-wikipedia-only-entities" aria-label="Permalink to &quot;OQ-2 — Allow Wikipedia-only entities?&quot;">​</a></h3><p><strong>Question.</strong> Some entities have no operator page (genuinely or because the operator is defunct). Allow Wikipedia-only?</p><p><strong>Decision.</strong> No. Every entity must have at least two distinct sources. When the operator is defunct (e.g. some Soviet missions), use the most authoritative secondary source (NSSDC, Lavochkin Association, scientific publisher). Wikipedia may stay as one of the links — never as the only one.</p><h3 id="oq-3-—-native-language-priority-versus-ui-locale-priority" tabindex="-1">OQ-3 — Native-language priority versus UI-locale priority? <a class="header-anchor" href="#oq-3-—-native-language-priority-versus-ui-locale-priority" aria-label="Permalink to &quot;OQ-3 — Native-language priority versus UI-locale priority?&quot;">​</a></h3><p><strong>Question.</strong> When a user is browsing in <code>es</code> and the entity is a CNSA mission, should the first link be Spanish Wikipedia (matches UI locale) or the Chinese CNSA page (matches operator)?</p><p><strong>Decision.</strong> UI-locale wins, then operator-native, then English, then multi-lingual. The reasoning: a Spanish-speaking user landing on Tianwen-1 still benefits more from the Chinese CNSA page than from English Wikipedia, but if a Spanish-language source from a credible publisher exists, it wins. The fallback is <em>additive</em>: native-language operator pages remain visible to every user, only their order changes.</p><h3 id="oq-4-—-rel-external-opt-in" tabindex="-1">OQ-4 — <code>rel=&quot;external&quot;</code> opt-in? <a class="header-anchor" href="#oq-4-—-rel-external-opt-in" aria-label="Permalink to &quot;OQ-4 — `rel=&quot;external&quot;` opt-in?&quot;">​</a></h3><p><strong>Question.</strong> Add <code>rel=&quot;external&quot;</code> to every outbound link, or only some?</p><p><strong>Decision.</strong> Every outbound link: <code>rel=&quot;noopener noreferrer external&quot;</code>. The semantic value (search-engine signal, screen-reader cue) outweighs the mild bloat. Not adding <code>rel=&quot;dofollow&quot;</code> or <code>rel=&quot;nofollow&quot;</code> — they are ambiguous and we don&#39;t want to make a SEO statement either way.</p><h3 id="oq-5-—-link-check-failure-policy" tabindex="-1">OQ-5 — Link-check failure policy? <a class="header-anchor" href="#oq-5-—-link-check-failure-policy" aria-label="Permalink to &quot;OQ-5 — Link-check failure policy?&quot;">​</a></h3><p><strong>Question.</strong> Should a single 404 on a <code>deep</code> link fail the build?</p><p><strong>Decision.</strong> No. <code>intro</code> and <code>core</code> 4xx/5xx fail <code>validate-data</code> because those are the links a user sees on a quick visit. <code>deep</code> warns in the diff report only — those links are the third-tier reference reading and are most likely to move (academic papers being archived, agency CMSes redirecting to new portals). Redirects always warn but never fail; <code>build-link-provenance</code> picks up the canonical URL on next refetch.</p><h3 id="oq-6-—-where-does-the-link-checker-live-in-the-build-pipeline" tabindex="-1">OQ-6 — Where does the link-checker live in the build pipeline? <a class="header-anchor" href="#oq-6-—-where-does-the-link-checker-live-in-the-build-pipeline" aria-label="Permalink to &quot;OQ-6 — Where does the link-checker live in the build pipeline?&quot;">​</a></h3><p><strong>Question.</strong> On every PR, on every refetch, both?</p><p><strong>Decision.</strong> Refetch only. CI does not have reliable outbound network for agency CMSes (rate limits, geo-fences). <code>npm run fetch</code> runs locally or on a maintainer-triggered job; <code>npm run build</code> and PR CI rely on <code>validate-data</code> reading the most recent <code>last-link-check.md</code> from the repo. The check is versioned alongside the manifest.</p><h3 id="oq-7-—-how-big-can-library-get" tabindex="-1">OQ-7 — How big can <code>/library</code> get? <a class="header-anchor" href="#oq-7-—-how-big-can-library-get" aria-label="Permalink to &quot;OQ-7 — How big can `/library` get?&quot;">​</a></h3><p><strong>Question.</strong> With 925 links, will a single-page render OK?</p><p><strong>Decision.</strong> Yes for v0.5.0. The <code>/credits</code> page already renders ~622 image rows and the page is fast. ~925 link rows ought to be fine. If the page crosses ~250 ms render time on a low-end device, the <code>docs/wip/learn-link-backlog.md</code> has a virtualisation backlog item.</p><h3 id="oq-8-—-page-name" tabindex="-1">OQ-8 — Page name? <a class="header-anchor" href="#oq-8-—-page-name" aria-label="Permalink to &quot;OQ-8 — Page name?&quot;">​</a></h3><p><strong>Question.</strong> What is the public page called?</p><p><strong>Decision.</strong> <code>/library</code>. Owner-chosen. Existing &quot;Mission Library&quot; UI label on <code>/missions</code> is renamed to <strong>Mission Catalog</strong> to free the word.</p><h2 id="rollout" tabindex="-1">Rollout <a class="header-anchor" href="#rollout" aria-label="Permalink to &quot;Rollout&quot;">​</a></h2><p>Five milestones, mirroring the L-A through L-E layout used for the imagery rollout (ADR-046 / ADR-047):</p><ul><li><strong>L-A</strong> (this RFC + ADR-051 + audit doc + backlog + index updates) — planning gate. Blocks everything else.</li><li><strong>L-B</strong> — provenance manifest infrastructure: <code>link-provenance.json</code> + AJV schema + <code>LinkCredit.svelte</code> + <code>build-link-provenance.ts</code> + <code>validate-data</code> integration + i18n keys + panel wiring. Blocks C/D/E.</li><li><strong>L-C</strong> — editorial enrichment of all non-US entities; native-language priority.</li><li><strong>L-D</strong> — <code>/library</code> route + Mission Catalog rename + footer link + library-grouping helper.</li><li><strong>L-E</strong> — <code>check-learn-links.ts</code> + chained into <code>npm run fetch</code> + fail-closed <code>intro</code>/<code>core</code> policy.</li></ul><p>Each milestone validates green (<code>typecheck</code>, <code>lint</code>, <code>test</code>, <code>validate-data</code>) and is committed and pushed independently before the next starts.</p><h2 id="acceptance-gates-per-milestone" tabindex="-1">Acceptance gates per milestone <a class="header-anchor" href="#acceptance-gates-per-milestone" aria-label="Permalink to &quot;Acceptance gates per milestone&quot;">​</a></h2><ul><li>L-A: ADR-051 committed; this RFC committed and closed; audit doc shipped.</li><li>L-B: every existing LEARN link has a provenance entry; <code>validate-data</code> green; <code>LinkCredit.svelte</code> renders under every panel link.</li><li>L-C: zero entities link to Wikipedia as their only source; non-US share rises from ~4 % to ≥ 15 %.</li><li>L-D: <code>/library</code> route renders all sources, grouped by source, newest first; Mission Catalog label landed in all 14 locales.</li><li>L-E: <code>npm run fetch</code> chains the link-checker; planted broken <code>intro</code> link fails <code>validate-data</code>; planted broken <code>deep</code> link warns.</li></ul><h2 id="out-of-scope" tabindex="-1">Out of scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of scope&quot;">​</a></h2><ul><li>Direct-permission outreach to agencies for content beyond their public sites → <a href="https://github.com/chipi/orrery/issues/46" target="_blank" rel="noreferrer">#46</a>.</li><li>NASA-partnership-credit imagery enrichment → <a href="https://github.com/chipi/orrery/issues/45" target="_blank" rel="noreferrer">#45</a>.</li><li>Tiangong Explorer (RFC-014) is unrelated despite the adjacent number.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li>ADR-046 — Agency-first build-time imagery sourcing.</li><li>ADR-047 — Provenance manifests + license stewardship.</li><li>ADR-051 — Outbound learn-link stewardship.</li><li>Epic <a href="https://github.com/chipi/orrery/issues/51" target="_blank" rel="noreferrer">#51</a> — LEARN-link stewardship rollout.</li></ul>',42)])])}const g=o(n,[["render",r]]);export{p as __pageData,g as default};
